print(predict(15, True))   # teen who likes music

def gini(labels):
    total = len(labels)
    if total == 0:
        return 0
    counts = {}
    for label in labels:
        counts[label] = counts.get(label, 0) + 1
    return 1 - sum((c / total) ** 2 for c in counts.values())

print(gini(["spam", "spam", "spam", "spam"]))  # pure
print(gini(["spam", "ham", "spam", "ham"]))   # impure
print(gini(["spam", "ham", "ham", "ham"]))    # mostly pure

