def gini(labels):
    total = len(labels)
    if total == 0:
        return 0
    counts = {}
    for label in labels:
        counts[label] = counts.get(label, 0) + 1
    return 1 - sum((c / total) ** 2 for c in counts.values())

def gini_split_score(left, right):
    total = len(left) + len(right)
    if total == 0:
        return 0
    weight_left  = len(left)  / total
    weight_right = len(right) / total
    return weight_left * gini(left) + weight_right * gini(right)

# Split A: age > 30
left_A  = ["buy", "buy", "buy", "no"]
right_A = ["no", "no", "buy"]

# Split B: income > 50k
left_B  = ["buy", "no", "buy", "no"]
right_B = ["buy", "buy", "no"]

score_A = gini_split_score(left_A, right_A)
score_B = gini_split_score(left_B, right_B)

print("Split A score:", round(score_A, 4))
print("Split B score:", round(score_B, 4))

if score_A < score_B:
    print("Split A is better (lower Gini = purer groups)")
else:
    print("Split B is better (lower Gini = purer groups)")
